const input = $input.first().json;
const body = input.body || input;

const email = (body.email || '').toLowerCase().trim();
const name = (body.name || '').trim();

if (!email || !name) {
  return [{ json: { error: true, message: 'Missing required fields: email and name are required' } }];
}

const today = new Date().toISOString().split('T')[0];
const idempotencyKey = `${email}_${today}`;

return [{ json: { email, name, company: (body.company || '').trim(), role: (body.role || '').trim(), company_size: body.company_size || '', budget: body.budget || '', message: body.message || '', source: body.source || 'unknown', idempotency_key: idempotencyKey } }];

const lead = $('Validate & Idempotency').first().json;
let score = 0;
const scoring_breakdown = [];

const sizeScores = { '1-10': 5, '10-50': 15, '50-200': 25, '200-1000': 30, '1000+': 20 };
const sizeScore = sizeScores[lead.company_size] || 10;
score += sizeScore;
scoring_breakdown.push({ factor: 'company_size', value: lead.company_size, points: sizeScore });

const roleStr = (lead.role || '').toLowerCase();
let roleScore = 10;
if (roleStr.includes('vp') || roleStr.includes('vice president') || roleStr.includes('director')) roleScore = 30;
else if (roleStr.includes('head of') || roleStr.includes('chief') || roleStr.includes('cxo') || roleStr.includes('ceo') || roleStr.includes('cmo') || roleStr.includes('cro')) roleScore = 35;
else if (roleStr.includes('manager')) roleScore = 20;
else if (roleStr.includes('founder') || roleStr.includes('owner')) roleScore = 30;
score += roleScore;
scoring_breakdown.push({ factor: 'role', value: lead.role, points: roleScore });

const budgetScores = { 'under-1k': 5, '1k-5k': 15, '5k-15k': 25, '15k-50k': 35, '50k+': 30 };
const budgetScore = budgetScores[lead.budget] || 10;
score += budgetScore;
scoring_breakdown.push({ factor: 'budget', value: lead.budget, points: budgetScore });

const msgLength = (lead.message || '').length;
let msgScore = 5;
if (msgLength > 200) msgScore = 20;
else if (msgLength > 100) msgScore = 15;
else if (msgLength > 50) msgScore = 10;
score += msgScore;
scoring_breakdown.push({ factor: 'message_quality', value: `${msgLength} chars`, points: msgScore });

let tier = 'cold';
if (score >= 80) tier = 'hot';
else if (score >= 50) tier = 'warm';

return [{ json: { ...lead, score, tier, scoring_breakdown } }];

const lead = $('Score Lead').first().json;
const input = $input.first().json;

try {
  const content = input.choices?.[0]?.message?.content;
  if (!content) throw new Error('No response content');
  const data = JSON.parse(content.replace(/```json\n?|```\n?/g, '').trim());
  return [{ json: { ...lead, icp_match: data } }];
} catch (err) {
  return [{ json: { ...lead, icp_match: null } }];
}

const lead = $('Parse ICP').first().json;
const saveResult = $input.first().json;
const id = saveResult.id;

let routed_to = 'nurture';
if (lead.tier === 'hot') routed_to = 'sales_urgent';
else if (lead.tier === 'warm') routed_to = 'sales_queue';

let notification = null;
if (lead.tier !== 'cold') {
  const icpSummary = lead.icp_match ? 'ICP Score: ' + lead.icp_match.icp_score + '/10' : 'ICP unavailable';
  notification = lead.tier === 'hot'
    ? { text: '🔥 *HOT LEAD* | ' + lead.name + ' (' + lead.company + ') | Score: ' + lead.score + '/100 | ' + lead.role + ' | Budget: ' + lead.budget + ' | ' + icpSummary }
    : { text: '📋 Warm Lead: ' + lead.name + ' (' + lead.company + ') | Score: ' + lead.score + '/100 | ' + lead.role };
}

return [{ json: { ...lead, id, routed_to, notification } }];

const lead = $('Route Lead').first().json;
const input = $input.first().json;

let auto_reply = null;
try {
  const content = input.choices?.[0]?.message?.content;
  if (content) {
    auto_reply = JSON.parse(content.replace(/```json\n?|```\n?/g, '').trim());
  }
} catch (err) {
  auto_reply = { subject: 'Thanks for reaching out!', body: 'Hi ' + lead.name + ', thank you for your interest in ColdIQ. We will be in touch shortly.' };
}

return [{ json: { ...lead, auto_reply } }];
